import{_ as e,o as t,c as s,e as a}from"./app-cb4a12e2.js";const o={};function r(i,n){return t(),s("div",null,[...n[0]||(n[0]=[a(`<h1 id="next-js-技术要点总结" tabindex="-1"><a class="header-anchor" href="#next-js-技术要点总结" aria-hidden="true">#</a> Next.js 技术要点总结</h1><p>Next.js 是基于 React 的全栈 Web 框架，旨在提供最佳的开发体验和高性能的 Web 应用。以下是其核心技术点总结：</p><h2 id="_1-渲染模式-rendering-patterns" tabindex="-1"><a class="header-anchor" href="#_1-渲染模式-rendering-patterns" aria-hidden="true">#</a> 1. 渲染模式 (Rendering Patterns)</h2><p>Next.js 最强大的特性之一是支持多种渲染模式，开发者可以根据页面需求灵活选择：</p><ul><li><strong>SSR (Server-Side Rendering)</strong>: <ul><li><strong>服务端渲染</strong>：每次请求都在服务器端动态生成 HTML。</li><li><strong>适用场景</strong>：实时数据更新、个性化内容、SEO 要求高的页面。</li><li><strong>实现</strong>：<code>getServerSideProps</code> (Pages Router) 或直接在 Server Component 中获取数据 (App Router)。</li></ul></li><li><strong>SSG (Static Site Generation)</strong>: <ul><li><strong>静态生成</strong>：在构建时（Build Time）生成 HTML。</li><li><strong>适用场景</strong>：博客文章、文档、营销页面。</li><li><strong>实现</strong>：<code>getStaticProps</code> (Pages Router) 或默认行为 (App Router)。</li></ul></li><li><strong>ISR (Incremental Static Regeneration)</strong>: <ul><li><strong>增量静态再生</strong>：允许在应用运行时更新静态页面，无需重新构建整个站点。</li><li><strong>机制</strong>：设置 <code>revalidate</code> 时间，超时后后台重新生成页面。</li></ul></li><li><strong>CSR (Client-Side Rendering)</strong>: <ul><li><strong>客户端渲染</strong>：传统的 React 渲染方式，浏览器加载 JS 后渲染。</li><li><strong>适用场景</strong>：交互性强、无需 SEO 的私有后台页面。</li></ul></li></ul><h2 id="_2-路由系统-routing" tabindex="-1"><a class="header-anchor" href="#_2-路由系统-routing" aria-hidden="true">#</a> 2. 路由系统 (Routing)</h2><h3 id="app-router-自-next-js-13-起" tabindex="-1"><a class="header-anchor" href="#app-router-自-next-js-13-起" aria-hidden="true">#</a> App Router (自 Next.js 13 起)</h3><ul><li><strong>基于文件系统</strong>：<code>app/</code> 目录下的文件夹结构映射 URL 路径。</li><li><strong>React Server Components (RSC)</strong>: 默认所有组件都是服务端组件，减少发送到客户端的 JavaScript 体积。</li><li><strong>特殊文件</strong>：<code>page.js</code> (页面 UI), <code>layout.js</code> (共享布局), <code>loading.js</code> (加载状态), <code>error.js</code> (错误处理), <code>not-found.js</code> (404).</li><li><strong>流式传输 (Streaming)</strong>: 利用 React Suspense 逐步发送 HTML，优化首字节时间 (TTFB)。</li></ul><h3 id="pages-router-传统模式" tabindex="-1"><a class="header-anchor" href="#pages-router-传统模式" aria-hidden="true">#</a> Pages Router (传统模式)</h3><ul><li><strong>基于文件系统</strong>：<code>pages/</code> 目录下的文件映射 URL。</li><li><strong>API Routes</strong>：<code>pages/api/</code> 目录下轻松创建后端 API 端点。</li></ul><h2 id="_3-数据获取-data-fetching" tabindex="-1"><a class="header-anchor" href="#_3-数据获取-data-fetching" aria-hidden="true">#</a> 3. 数据获取 (Data Fetching)</h2><ul><li><strong>扩展的 fetch API</strong> (App Router): Next.js 扩展了原生 <code>fetch</code>，增加了缓存和重新验证控制。<div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 类似于 getStaticProps</span>
<span class="token function">fetch</span><span class="token punctuation">(</span><span class="token string">&#39;https://...&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token literal-property property">cache</span><span class="token operator">:</span> <span class="token string">&#39;force-cache&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token comment">// 类似于 getServerSideProps</span>
<span class="token function">fetch</span><span class="token punctuation">(</span><span class="token string">&#39;https://...&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token literal-property property">cache</span><span class="token operator">:</span> <span class="token string">&#39;no-store&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token comment">// ISR</span>
<span class="token function">fetch</span><span class="token punctuation">(</span><span class="token string">&#39;https://...&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token literal-property property">next</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">revalidate</span><span class="token operator">:</span> <span class="token number">10</span> <span class="token punctuation">}</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><strong>Server Actions</strong>: 允许在组件中直接调用异步服务端函数来处理数据突变（Mutations），无需手动创建 API 路由。</li></ul><h2 id="_4-性能优化-optimizations" tabindex="-1"><a class="header-anchor" href="#_4-性能优化-optimizations" aria-hidden="true">#</a> 4. 性能优化 (Optimizations)</h2><ul><li><strong>Image Optimization (<code>&lt;Image&gt;</code>)</strong>: 自动调整图片大小、格式转换 (WebP/AVIF)、懒加载，防止累积布局偏移 (CLS)。</li><li><strong>Font Optimization (<code>next/font</code>)</strong>: 自动托管 Google Fonts，零布局偏移。</li><li><strong>Script Optimization (<code>&lt;Script&gt;</code>)</strong>: 控制第三方脚本的加载策略 (<code>beforeInteractive</code>, <code>afterInteractive</code>, <code>lazyOnload</code>)。</li><li><strong>Turbopack</strong>: 基于 Rust 的增量打包引擎，开发服务器启动速度极快（Webpack 的替代者）。</li></ul><h2 id="_5-中间件-middleware" tabindex="-1"><a class="header-anchor" href="#_5-中间件-middleware" aria-hidden="true">#</a> 5. 中间件 (Middleware)</h2><ul><li>在请求完成之前运行代码。</li><li><strong>用途</strong>：重写、重定向、身份验证检查、修改请求/响应头、A/B 测试。</li><li><strong>运行时</strong>：基于 Edge Runtime，启动速度快，但不支持所有 Node.js API。</li></ul><h2 id="_6-部署与生态" tabindex="-1"><a class="header-anchor" href="#_6-部署与生态" aria-hidden="true">#</a> 6. 部署与生态</h2><ul><li><strong>Vercel</strong>: Next.js 的开发团队出品，提供零配置部署、Edge Network、Serverless Functions 支持。</li><li><strong>Node.js Server</strong>: 支持传统的 Node.js 服务器部署（Docker 容器化）。</li><li><strong>Static Export</strong>: <code>output: &#39;export&#39;</code> 支持导出为纯静态 HTML/CSS/JS，可部署在 Nginx、S3 等任何静态主机上。</li></ul><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>Next.js 不仅仅是一个 UI 框架，更是一个<strong>全栈元框架 (Meta-Framework)</strong>。它通过 App Router 和 Server Components 模糊了前后端的界限，极大地简化了数据流向，同时通过内置的各种优化手段，保证了应用的极致性能和 SEO 友好性。</p>`,20)])])}const c=e(o,[["render",r],["__file","next.html.vue"]]);export{c as default};
